test_cases.assertion_pseudocode:
customClient := &http.Client{Timeout: 30 * time.Second}
p := NewGitHubProvider("cid", "secret", "", "", "", customClient)
assert p.httpClient == customClient

for each uri in ["http://localhost:9000/cb", "http://localhost:1/cb", "http://localhost:65535/cb", "http://localhost:54321/callback/foo"]:
  err := ValidateRedirectURI(uri, externalURL="")
  assert err == nil

for each uri in ["https://api.example.com/callback", "https://api.example.com/auth/callback/extra"]:
  err := ValidateRedirectURI(uri, externalURL="https://api.example.com")
  assert err == nil

// Use real SQLite DB
resp := httpPost("/auth/callback", {provider:"github", code:"abc", redirect_uri:"http://localhost:9000/cb"})
assert resp.statusCode == 200
// Verify user exists in DB (it was created)
row := db.QueryRow("SELECT id FROM users WHERE provider='github' AND provider_id='99'")
assert row != nil

// Static check: grep -r "math/rand" internal/oauth/ returns no results
// Functional check:
for i in range(1000):
  keyID1 := generateKeyID()
  keyID2 := generateKeyID()
  assert keyID1 != keyID2 // extremely unlikely if truly random
// Verify entropy: collect 100 key_ids, assert no duplicates
ids := set()
for i in range(100):
  ids.add(generateKeyID())
assert len(ids) == 100

wg := WaitGroup
errs := []error
for i in [1, 2]:
  go func():
    resp := httpPost("/auth/callback", validBody)
    if resp.statusCode != 200: errs.append(error)
    wg.Done()
wg.Wait()
assert len(errs) == 0
// No panic, no deadlock

