// This is a compile-time check; include in a build-tag-guarded file:
// //go:build ignore
type incompleteProvider struct{}
func (p *incompleteProvider) Name() string { return "incomplete" }
func (p *incompleteProvider) AuthorizeURL(s, r string) string { return "" }
// Missing Exchange and UserInfo
var _ Provider = &incompleteProvider{} // must NOT compile

mockProvider.Exchange = func(ctx, code, redirectURI) {
  <-ctx.Done()
  return "", ctx.Err()
}
ctx, cancel := contextWithTimeout(50 * time.Millisecond)
resp := httpPostWithContext(ctx, "/auth/callback", validBody)
cancel()
// verify no goroutine leak via runtime.NumGoroutine() before and after
